INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, 16, 10031001, "闇属性ボーナス特大アップ", "闇属性のキャラが４体以上編成されているとき、キャラの属性ボーナスが強化される。闇属性以外の属性ボーナスを無効化する。");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, 18, 10031002, "ダメージ減衰", "すべてのモンスターが一度の行動で受けるダメージ値を減衰させる。ダメージ値が上昇するほど減衰率も上昇する。");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, "boss_def_lower_limit", 10031003, "物理防御力（ダウン不可）アップ", "バトル開始時、すべてのモンスターの物理防御力を大アップさせる。この効果は物理防御力ダウンの影響を受けない。");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, "boss_magic_def_lower_limit", 10031004, "魔法防御力（ダウン不可）アップ", "バトル開始時、すべてのモンスターの魔法防御力を大アップさせる。この効果は魔法防御力ダウンの影響を受けない。");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, "boss_tp_down_cut", 10031005, "ＴＰダウンカット", "バトル開始時、すべてのモンスターがＴＰダウン\n75％カット状態になる。");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, 3, 10031006, "ＴＰ上昇ダウン", "バトル開始時、すべてのキャラのＴＰ上昇を中ダウンさせる。");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (4100310, 9, 10031007, "ＨＰ吸収ダウン", "バトル開始時、すべてのキャラのＨＰ吸収を特大ダウンさせる。");
